text:['"[{\"start\":0,\"editorState\":{\"blocks\":[{\"key\":\"alo9\",\"text\":\"Como hemos visto a lo largo de esta capacitación, la fatiga visual puede presentarse durante el trabajo prolongado frente a pantallas. Identificar sus síntomas, reconocer los factores de riesgo y aplicar medidas de ergonomía visual, así como realizar pausas periódicas, ayuda a proteger la salud visual durante la jornada laboral.\\nGracias por participar en esta capacitación.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":375,\"style\":\"textShadowBlur:8px\"},{\"offset\":0,\"length\":375,\"style\":\"backgroundColor:unset\"},{\"offset\":0,\"length\":375,\"style\":\"WebkitTextStrokeWidth:1px\"},{\"offset\":0,\"length\":375,\"style\":\"hlnkt:wp\"},{\"offset\":0,\"length\":375,\"style\":\"fontStyle:normal\"},{\"offset\":0,\"length\":375,\"style\":\"mobile-fontSize:24\"},{\"offset\":0,\"length\":375,\"style\":\"defaultTextStrokeWidth:1px\"},{\"offset\":0,\"length\":375,\"style\":\"WebkitTextStrokeColor:#F1EEE6\"},{\"offset\":0,\"length\":375,\"style\":\"textOutlineEnable:false\"},{\"offset\":0,\"length\":375,\"style\":\"opacity:1\"},{\"offset\":0,\"length\":375,\"style\":\"defaultTextStrokeColor:#F1EEE6\"},{\"offset\":0,\"length\":375,\"style\":\"hlnke:true\"},{\"offset\":0,\"length\":375,\"style\":\"defaultTextShadow:none\"},{\"offset\":0,\"length\":375,\"style\":\"tablet-fontSize:24\"},{\"offset\":0,\"length\":375,\"style\":\"textShadow:none\"},{\"offset\":0,\"length\":375,\"style\":\"textShadowX:0px\"},{\"offset\":0,\"length\":375,\"style\":\"fontStretch:normal\"},{\"offset\":0,\"length\":375,\"style\":\"fontType:regular\"},{\"offset\":0,\"length\":375,\"style\":\"color:#ffffff\"},{\"offset\":0,\"length\":375,\"style\":\"defaultBackgroundColor:#E8D01B\"},{\"offset\":0,\"length\":375,\"style\":\"textShadowY:4px\"},{\"offset\":0,\"length\":375,\"style\":\"textShadowColor:#F1EEE61F\"},{\"offset\":0,\"length\":375,\"style\":\"lineHeight:135%\"},{\"offset\":0,\"length\":375,\"style\":\"letterSpacing:0%\"},{\"offset\":0,\"length\":375,\"style\":\"textHighlightEnable:false\"},{\"offset\":0,\"length\":375,\"style\":\"textTransform:none\"},{\"offset\":0,\"length\":375,\"style\":\"textShadowOpacity:none\"},{\"offset\":0,\"length\":375,\"style\":\"overridden:true\"},{\"offset\":0,\"length\":375,\"style\":\"textDecoration:none\"},{\"offset\":0,\"length\":375,\"style\":\"fontFamily:Georgia\"},{\"offset\":0,\"length\":375,\"style\":\"borderBottomStyle:none\"},{\"offset\":0,\"length\":375,\"style\":\"textShadowEnable:false\"},{\"offset\":0,\"length\":375,\"style\":\"hlnk:\"},{\"offset\":0,\"length\":375,\"style\":\"fontWeight:normal\"},{\"offset\":0,\"length\":375,\"style\":\"desktop-fontSize:12\"}],\"entityRanges\":[],\"data\":{\"listDepth\":\"0\",\"listColor\":\"#666666\",\"listIndent\":\"100%\",\"verticalAlign\":\"middle\",\"overridden\":\"true\",\"marginLeft\":\"0px\",\"listType\":\"S_Bullets08\",\"textAlign\":\"center\",\"marginBottom\":\"0%\",\"presetId\":\"text-closedcaptions\",\"listSize\":\"100%\"}}],\"entityMap\":{}},\"CCPosition\":\"BOTTOM\",\"text\":\"Como hemos visto a lo largo de esta capacitación, la fatiga visual puede presentarse durante el trabajo prolongado frente a pantallas. Identificar sus síntomas, reconocer los factores de riesgo y aplicar medidas de ergonomía visual, así como realizar pausas periódicas, ayuda a proteger la salud visual durante la jornada laboral.\\nGracias por participar en esta capacitación.\",\"duration\":22.9,\"end\":22.9,\"id\":\"caption__6143__17\",\"dirtyReasons\":[],\"speechAgentV1\":{\"name\":\"Dan Dan\",\"voiceId\":{\"uid\":\"9F4C8ztpNUmXkdDDbz3J\",\"modelId\":\"1\"},\"source\":\"AIVoices\"}}]"']
